import{_ as a,c as r,o as i,a4 as o}from"./chunks/framework.Cjj1onnZ.js";const t="/images/intro/%E6%8F%92%E4%BB%B6%E7%B3%BB%E7%BB%9F%E7%9A%84%E5%85%B3%E7%B3%BB%E8%A7%86%E5%9B%BE.svg",m=JSON.parse('{"title":"关于插件","description":"","frontmatter":{},"headers":[],"relativePath":"zh/01-intro/01-about.md","filePath":"zh/01-intro/01-about.md"}'),n={name:"zh/01-intro/01-about.md"};function l(c,e,h,d,s,b){return i(),r("div",{"data-pagefind-body":!0},e[0]||(e[0]=[o('<h1 id="关于插件" tabindex="-1">关于插件 <a class="header-anchor" href="#关于插件" aria-label="Permalink to “关于插件”">​</a></h1><h2 id="插件是什么" tabindex="-1">插件是什么 <a class="header-anchor" href="#插件是什么" aria-label="Permalink to “插件是什么”">​</a></h2><ul><li>插件系统提供了一个完整的框架，可以让生态合作方、外部开发者按照一定的规则开发应用并运行在捷勃特的机器人中。</li><li>Copper/Bronze 系统允许运行 3 种用户自定义的程序： Web 小程序、简单服务、通用服务。</li></ul><p>以 Copper 为例，他们的关系如下：</p><figure><img src="'+t+'" alt=""></figure><h2 id="插件分类" tabindex="-1">插件分类 <a class="header-anchor" href="#插件分类" aria-label="Permalink to “插件分类”">​</a></h2><h3 id="web小程序-webminiprogram" tabindex="-1">Web 小程序 <code>webMiniProgram</code> <a class="header-anchor" href="#web小程序-webminiprogram" aria-label="Permalink to “Web小程序 webMiniProgram”">​</a></h3><p>Web 小程序允许开发者通过 Web 技术（如 HTML、CSS、JavaScript）编写插件的前端界面。并将其嵌入到系统的 Web 页面中，作为前端页面进行展示和交互。</p><h3 id="简单服务-easyservice" tabindex="-1">简单服务 <code>easyService</code> <a class="header-anchor" href="#简单服务-easyservice" aria-label="Permalink to “简单服务 easyService”">​</a></h3><p>简单服务插件是一个通过编写一个或多个 Python 方法来实现功能的插件。它允许开发者快速实现一个简单的后端功能，通过 HTTP 请求与系统交互。简单服务通常不涉及复杂的框架或外部依赖，只需要编写一些方法即可。</p><h3 id="通用服务-generalservice" tabindex="-1">通用服务 <code>generalService</code> <a class="header-anchor" href="#通用服务-generalservice" aria-label="Permalink to “通用服务 generalService”">​</a></h3><p>通用服务插件可提供更强大的功能支持。它通常是一个功能更复杂的后端服务，能够进行数据处理、复杂的逻辑运算，或者与外部系统交互。</p><h2 id="插件文件组成" tabindex="-1">插件文件组成 <a class="header-anchor" href="#插件文件组成" aria-label="Permalink to “插件文件组成”">​</a></h2><h3 id="配置文件" tabindex="-1">配置文件 <a class="header-anchor" href="#配置文件" aria-label="Permalink to “配置文件”">​</a></h3><p>任何类型的插件必须包含 <code>config.json</code> 文件，即<a href="./../03-reference/01-config.html">配置文件</a>。只有包含配置文件才能安装、初始化、运行。</p><h3 id="数据文件" tabindex="-1">数据文件 <a class="header-anchor" href="#数据文件" aria-label="Permalink to “数据文件”">​</a></h3><p>后台插件包中一般都包含一个 data 目录，其中用于存储插件运行时生成的数据。具体可参考<a href="./../02-development/03-advanced/04-data-persistence.html">数据持久化</a>。</p>',17)]))}const f=a(n,[["render",l]]);export{m as __pageData,f as default};
